    try:
        date_str = date_str.strip()
        patterns = [
            r'(\w+)[,.\s]*(\d{1,2})[a-zA-Z]{0,2}[,\s]*(\d{4})',  # "Aug 3rd, 2021" or "March 2nd, 2021"
            r'(\d{4})[,\s]*(\w+)[,.\s]*(\d{1,2})',                # "2020, April 7th"
            r'(\d{1,2})[a-zA-Z]{0,2}[,.\s]*(\w+)[,.\s]*(\d{4})', # "30th June 2020"
            r'(\d{1,2})\s+(\w+)\s+(\d{4})',                      # "9th Nov 2021"
        ]

